1298	static common_chat_params common_chat_params_init_lfm2(const common_chat_template &    tmpl,
1299	                                                       const autoparser::generation_params & inputs) {
1300	    common_chat_params data;
1301	
1302	    data.prompt            = common_chat_template_direct_apply_impl(tmpl, inputs);
1303	    data.format            = COMMON_CHAT_FORMAT_PEG_NATIVE;
1304	    data.supports_thinking = true;
1305	    data.preserved_tokens  = {
1306	        "<|tool_list_start|>",
1307	        "<|tool_list_end|>",
1308	        "<|tool_call_start|>",
1309	        "<|tool_call_end|>",
1310	        "<think>",
1311	        "</think>",
1312	    };
1313	
1314	    auto has_tools         = inputs.tools.is_array() && !inputs.tools.empty();
1315	    auto extract_reasoning = inputs.reasoning_format != COMMON_REASONING_FORMAT_NONE;
1316	    auto include_grammar   = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;
1317	
1318	    const std::string TOOL_CALL_START = "<|tool_call_start|>";
1319	    const std::string TOOL_CALL_END   = "<|tool_call_end|>";
1320	    const std::string THINK_START     = "<think>";
1321	    const std::string THINK_END       = "</think>";
1322	
1323	    data.thinking_start_tag = THINK_START;
1324	    data.thinking_end_tag   = THINK_END;
1325	
1326	    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
1327	        auto generation_prompt = p.prefix(inputs.generation_prompt, THINK_START);
1328	        auto end = p.end();
1329	
1330	        auto reasoning = p.eps();
1331	        if (extract_reasoning && inputs.enable_thinking) {
1332	            reasoning = p.optional(THINK_START + p.reasoning(p.until(THINK_END)) + THINK_END);
1333	        }
1334	
1335	        if (!has_tools || inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_NONE) {
1336	            return generation_prompt + reasoning + p.content(p.rest()) + end;
1337	        }
1338	        auto tool_calls = p.rule("tool-calls",
1339	            p.trigger_rule("tool-call",
1340	                p.literal(TOOL_CALL_START) +
1341	                p.python_style_tool_calls(inputs.tools, inputs.parallel_tool_calls) +
1342	                p.literal(TOOL_CALL_END)
1343	            )
1344	        );
1345	
1346	        auto content = p.content(p.until(TOOL_CALL_START));
1347	
1348	        return generation_prompt + reasoning + content + tool_calls + end;
1349	    });
1350	
1351	    data.parser = parser.save();
1352	
1353	    if (include_grammar) {
1354	        data.grammar_lazy = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;
1355	        data.grammar      = build_grammar([&](const common_grammar_builder & builder) {
1356	            foreach_function(inputs.tools, [&](const json & tool) {
1357	                const auto & function = tool.at("function");
1358	                auto         schema   = function.at("parameters");
1359	                builder.resolve_refs(schema);
1360	            });
1361	            parser.build_grammar(builder, data.grammar_lazy);
1362	        });
1363	
1364	        data.grammar_triggers = {
1365	            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, TOOL_CALL_START }
1366	        };
1367	    }
1368	    return data;
1369	}
